∀ {P : Core.Problem} {S : CT17.Spec P} {C : CT17.Capability S} {context : Core.BranchContext P}
  {_invocation : CT17.Input S C context} (self : CT17.IncompatibilityResidual S C context _invocation),
  ¬S.Compatible context self.target self.offset

∀ {P : Core.Problem} {S : CT17.Spec P} {C : CT17.Capability S} {context : Core.BranchContext P}
  {invocation : CT17.Input S C context} {_compatible : CT17.CompatibleState S C context invocation},
  CT17.FiniteScaleState S C context invocation _compatible → invocation.scale ≤ C.finiteScaleLimit

∀ {P : Core.Problem} {S : CT17.Spec P} {C : CT17.Capability S} {context : Core.BranchContext P}
  {invocation : CT17.Input S C context} {_compatible : CT17.CompatibleState S C context invocation},
  CT17.OrbitScaleState S C context invocation _compatible → C.finiteScaleLimit < invocation.scale

∀ {P : Core.Problem} {S : CT17.Spec P} {C : CT17.Capability S} {context : Core.BranchContext P}
  {invocation : CT17.Input S C context} {_compatible : CT17.CompatibleState S C context invocation},
  invocation.scale ≤ C.finiteScaleLimit → CT17.FiniteScaleState S C context invocation _compatible

∀ {P : Core.Problem} {S : CT17.Spec P} {C : CT17.Capability S} {context : Core.BranchContext P}
  {invocation : CT17.Input S C context} {_compatible : CT17.CompatibleState S C context invocation},
  C.finiteScaleLimit < invocation.scale → CT17.OrbitScaleState S C context invocation _compatible

∀ {P : Core.Problem} {S : CT17.Spec P} {capability : CT17.Capability S} {ctx : Core.BranchContext P}
  {input : CT17.Input S capability ctx} {compatible : CT17.CompatibleState S capability ctx input}
  {finite : CT17.FiniteScaleState S capability ctx input compatible}
  (self : CT17.ExhaustedCertificate S capability ctx input) (position : S.Position input.scale),
  ¬CT17.Survives S capability ctx input position

∀ {P : Core.Problem} {S : CT17.Spec P} {capability : CT17.Capability S} {ctx : Core.BranchContext P}
  {input : CT17.Input S capability ctx} {compatible : CT17.CompatibleState S capability ctx input}
  {finite : CT17.FiniteScaleState S capability ctx input compatible}
  (self : CT17.SurvivorEnumeration S capability ctx input finite) (position : S.Position input.scale),
  CT17.Survives S capability ctx input position → position ∈ self.survivors

∀ {P : Core.Problem} {S : CT17.Spec P} {capability : CT17.Capability S} {ctx : Core.BranchContext P}
  {input : CT17.Input S capability ctx} {compatible : CT17.CompatibleState S capability ctx input}
  {finite : CT17.FiniteScaleState S capability ctx input compatible}
  (self : CT17.SurvivorEnumeration S capability ctx input finite),
  ∀ position ∈ self.survivors, CT17.Survives S capability ctx input position

∀ {P : Core.Problem} {S : CT17.Spec P} {capability : CT17.Capability S} {ctx : Core.BranchContext P}
  {input : CT17.Input S capability ctx} {compatible : CT17.CompatibleState S capability ctx input}
  {finite : CT17.FiniteScaleState S capability ctx input compatible}
  (self : CT17.SurvivorResidual S capability ctx input), self.enumeration.survivors = self.first :: self.remaining

∀ {P : Core.Problem} {S : CT17.Spec P} {capability : CT17.Capability S} {ctx : Core.BranchContext P}
  {input : CT17.Input S capability ctx} {compatible : CT17.CompatibleState S capability ctx input}
  {orbit : CT17.OrbitScaleState S capability ctx input compatible}
  (self : CT17.OrbitResidual S capability ctx input orbit), CT17.OrbitAvoids S capability ctx input

∀ {P : Core.Problem} {S : CT17.Spec P} {capability : CT17.Capability S} {ctx : Core.BranchContext P}
  {input : CT17.Input S capability ctx} {compatible : CT17.CompatibleState S capability ctx input}
  {orbit : CT17.OrbitScaleState S capability ctx input compatible}
  (self : CT17.OrbitResidual S capability ctx input orbit),
  self.values = List.map (S.orbitValue ctx input.scale) capability.offsets.orderedValues

∀ {P : Core.Problem} {S : CT17.Spec P} {capability : CT17.Capability S} {ctx : Core.BranchContext P}
  {input : CT17.Input S capability ctx} {compatible : CT17.CompatibleState S capability ctx input}
  {orbit : CT17.OrbitScaleState S capability ctx input compatible}
  (self : CT17.TargetHitCertificate S capability ctx input orbit),
  S.orbitValue ctx input.scale self.offset = S.targetValue self.target
